package com.flowmind.common.security;import java.nio.charset.StandardCharsets;import java.time.Instant;import java.util.Base64;public final class TokenUtil{private TokenUtil(){}public static String createMockToken(String username){String raw=username+":"+Instant.now().plusSeconds(86400).getEpochSecond();return "mock-jwt."+Base64.getUrlEncoder().withoutPadding().encodeToString(raw.getBytes(StandardCharsets.UTF_8));}public static boolean isValid(String token){return token!=null&&token.startsWith("Bearer mock-jwt.");}}
